# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from flask import Flask, request, jsonify, send_file, abort
import os
from pathlib import Path
from datetime import datetime

app = Flask(__name__)

BASE_UPLOAD_DIR = os.environ.get("UPLOAD_ROOT", os.path.abspath("uploads"))


def get_user_root():
    root = request.args.get("root", "").strip()
    if not root:
        return None
    root_path = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, root))
    if not root_path.startswith(os.path.abspath(BASE_UPLOAD_DIR) + os.sep) and root_path != os.path.abspath(BASE_UPLOAD_DIR):
        return None
    return root_path


def safe_full_path(root_dir, relative_path):
    relative_path = relative_path or ""
    normalized = os.path.normpath(relative_path)
    full_path = os.path.normpath(os.path.join(root_dir, normalized))
    root_dir_abs = os.path.abspath(root_dir)
    full_path_abs = os.path.abspath(full_path)
    if full_path_abs != root_dir_abs and not full_path_abs.startswith(root_dir_abs + os.sep):
        return None
    return full_path_abs


def file_info(path):
    stat = os.stat(path)
    return {
        "name": os.path.basename(path),
        "path": path,
        "size": stat.st_size,
        "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
        "created": datetime.fromtimestamp(stat.st_ctime).isoformat(),
        "is_dir": os.path.isdir(path),
        "is_file": os.path.isfile(path),
    }


@app.route("/files", methods=["GET"])
def list_directory():
    root_dir = get_user_root()
    if not root_dir:
        return jsonify({"error": "Invalid or missing root"}), 400

    rel_path = request.args.get("path", "")
    target = safe_full_path(root_dir, rel_path)
    if not target or not os.path.exists(target):
        return jsonify({"error": "Path not found"}), 404
    if not os.path.isdir(target):
        return jsonify({"error": "Not a directory"}), 400

    items = []
    for name in sorted(os.listdir(target)):
        item_path = os.path.join(target, name)
        items.append({
            "name": name,
            "path": os.path.relpath(item_path, root_dir).replace("\\", "/"),
            "is_dir": os.path.isdir(item_path),
            "is_file": os.path.isfile(item_path),
        })

    return jsonify({
        "root": root_dir,
        "path": os.path.relpath(target, root_dir).replace("\\", "/") if target != root_dir else "",
        "items": items,
    })


@app.route("/download", methods=["GET"])
def download_file():
    root_dir = get_user_root()
    if not root_dir:
        return jsonify({"error": "Invalid or missing root"}), 400

    rel_path = request.args.get("path", "")
    target = safe_full_path(root_dir, rel_path)
    if not target or not os.path.exists(target):
        return jsonify({"error": "File not found"}), 404
    if not os.path.isfile(target):
        return jsonify({"error": "Not a file"}), 400

    return send_file(target, as_attachment=True)


@app.route("/info", methods=["GET"])
def get_info():
    root_dir = get_user_root()
    if not root_dir:
        return jsonify({"error": "Invalid or missing root"}), 400

    rel_path = request.args.get("path", "")
    target = safe_full_path(root_dir, rel_path)
    if not target or not os.path.exists(target):
        return jsonify({"error": "Path not found"}), 404

    info = file_info(target)
    info["relative_path"] = os.path.relpath(target, root_dir).replace("\\", "/")
    return jsonify(info)


@app.errorhandler(404)
def not_found(_):
    return jsonify({"error": "Not found"}), 404


@app.errorhandler(400)
def bad_request(_):
    return jsonify({"error": "Bad request"}), 400


if __name__ == "__main__":
    os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)), debug=True)